package com.hospital.management.validation;import com.hospital.management.model.BedForm;import java.util.*;/** Validates bed administration input. */public class BedValidator{private static final Set<String>S=Set.of("AVAILABLE","OCCUPIED","MAINTENANCE","INACTIVE");public ValidationResult validate(BedForm f){ValidationResult v=new ValidationResult();if(f==null){v.addError("form","Bed is required");return v;}if(f.getRoomId()==null||f.getRoomId()<=0)v.addError("roomId","Select a room");String n=f.getBedNumber()==null?"":f.getBedNumber().trim();if(!n.matches("[A-Za-z0-9/-]{1,30}"))v.addError("bedNumber","Use 1-30 letters, digits, hyphen or slash");if(f.getStatus()==null||!S.contains(f.getStatus().toUpperCase()))v.addError("status","Invalid status");return v;}}
